source:
/**
 * Builder.jsx ΓÇö Enterprise BI Query Builder & Chart Config
 *
 * Features:
 *  - Schema explorer with tree expand/collapse
 *  - DRAG-and-drop columns onto X / Y / Group-By zones (HTML5 + click fallback)
 *  - Drop zone highlight on dragover
 *  - Smart auto-suggestion on field selection
 *  - Inline validation warnings
 *  - SQL preview panel (live generated query)
 *  - Full 14-type chart picker
 *  - Color theme (6 themes), aggregation, legend, grid, smooth controls
 *  - Live real-time preview (updates on every change)
 *  - Edit mode (pre-loaded from dashboard)
 */
import React, { useState, useCallback, useEffect, useRef, memo } from "react";
import { useNavigate } from "react-router-dom";
import { Line, Area, Column, Pie, Scatter } from "@ant-design/charts";
import { useStore } from "./store";
import { schema, TYPE_BADGE, TYPE_COLOR } from "./mockData";
import { suggestChartType, validateChartConfig, CHART_TYPES } from "./utils/chartSuggestion";
import { buildChartConfig, getColorPalette, COLOR_THEMES } from "./utils/chartUtils";
import { buildQuery } from "./utils/queryEngine";
import ChartErrorBoundary from "./components/ChartErrorBoundary";

// ΓöÇΓöÇΓöÇ Drag data key ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const DRAG_KEY = "bi-field";

// ΓöÇΓöÇΓöÇ Schema Tree ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const SchemaTree = memo(function SchemaTree({ onFieldAssign, selectedDb, selectedTable, xField, yField, groupField }) {
  const [openDbs,    setOpenDbs]    = useState(() => new Set(Object.keys(schema)));
  const [openTables, setOpenTables] = useState(() => new Set());

  const toggle = (set, setFn, key) =>
    setFn((prev) => { const next = new Set(prev); next.has(key) ? next.delete(key) : next.add(key); return next; });

  function handleDragStart(e, db, tbl, field) {
    e.dataTransfer.effectAllowed = "copy";
    e.dataTransfer.setData(DRAG_KEY, JSON.stringify({ db, tbl, field }));
  }

  return (
    <aside className="schema-tree" aria-label="Schema Explorer">
      <div className="schema-tree-header">
        <span className="schema-tree-icon">≡ƒùä</span> Schema Explorer
      </div>
      {Object.entries(schema).map(([db, tables]) => (
        <div key={db}>
          <button
            className="tree-db"
            onClick={() => toggle(openDbs, setOpenDbs, db)}
            aria-expanded={openDbs.has(db)}
          >
            <span className="tree-arrow">{openDbs.has(db) ? "Γû╛" : "Γû╕"}</span>
            <span className="tree-db-icon">≡ƒùä</span>
            {db}
          </button>

          {openDbs.has(db) && Object.entries(tables).map(([tbl, info]) => {
            const tableKey = `${db}.${tbl}`;
            const isOpen   = openTables.has(tableKey);
            const isActive = selectedDb === db && selectedTable === tbl;
            return (
              <div key={tbl}>
                <button
                  className={`tree-table${isActive ? " active" : ""}`}
                  onClick={() => toggle(openTables, setOpenTables, tableKey)}
                  aria-expanded={isOpen}
                >
                  <span className="tree-arrow">{isOpen ? "Γû╛" : "Γû╕"}</span>
                  <span className="tree-table-icon">≡ƒôï</span>
                  {tbl}
                  <span className="tree-count">{info.fields.length}</span>
                </button>

                {isOpen && info.fields.map((field) => {
                  const isX = selectedTable === tbl && field.name === xField;
                  const isY = selectedTable === tbl && field.name === yField;
                  const isG = selectedTable === tbl && field.name === groupField;
                  return (
                    <button
                      key={field.name}
                      className={`tree-field clickable${isX ? " axis-x" : ""}${isY ? " axis-y" : ""}${isG ? " axis-g" : ""}`}
                      draggable="true"
                      onDragStart={(e) => handleDragStart(e, db, tbl, field)}
                      onClick={() => onFieldAssign(db, tbl, field, null)}
                      title={`${field.name} (${field.type}) ΓÇö drag or click to assign`}
                    >
                      <span className="field-type-dot" style={{ background: TYPE_COLOR[field.type] }} />
                      <span className="tree-field-name">{field.name}</span>
                      <span className="tree-field-badge" style={{ color: TYPE_COLOR[field.type] }}>
                        {TYPE_BADGE[field.type]}
                      </span>
                      {isX && <span className="tree-axis-pill x">X</span>}
                      {isY && <span className="tree-axis-pill y">Y</span>}
                      {isG && <span className="tree-axis-pill g">G</span>}
                      <span className="drag-hint-icon" aria-hidden="true">Γá┐</span>
                    </button>
                  );
                })}
              </div>
            );
          })}
        </div>
      ))}
    </aside>
  );
});

// ΓöÇΓöÇΓöÇ Field Drop Zone ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function FieldZone({ label, field, type, onClear, accent, zone, onDrop }) {
  const [dragOver, setDragOver] = useState(false);

  function handleDragOver(e) {
    e.preventDefault();
    e.dataTransfer.dropEffect = "copy";
    setDragOver(true);
  }

  function handleDrop(e) {
    e.preventDefault();
    setDragOver(false);
    try {
      const payload = JSON.parse(e.dataTransfer.getData(DRAG_KEY));
      if (payload?.field) onDrop(payload.field, zone);
    } catch {}
  }

  const isEmpty = !field;
  return (
    <div
      className={`field-zone${isEmpty ? " empty" : " filled"}${dragOver ? " drag-over" : ""}`}
      style={!isEmpty ? { borderColor: accent ?? TYPE_COLOR[type] } : undefined}
      aria-label={`${label} drop zone${isEmpty ? " ΓÇö empty" : ` ΓÇö ${field}`}`}
      aria-dropeffect="copy"
      onDragOver={handleDragOver}
      onDragLeave={() => setDragOver(false)}
      onDrop={handleDrop}
    >
      <span className="zone-label">{label}</span>
      {isEmpty ? (
        <span className="zone-hint">
          <span className="zone-drop-icon">Γç⌐</span> Drop or click a column
        </span>
      ) : (
        <>
          <span className="zone-field" style={{ color: accent ?? TYPE_COLOR[type] }}>{field}</span>
          <span className="zone-type">{TYPE_BADGE[type]}</span>
          <button className="zone-clear" onClick={onClear} aria-label={`Clear ${label}`}>├ù</button>
        </>
      )}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Chart Type Picker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ChartTypePicker({ value, suggestion, onChange }) {
  const groups = [...new Set(CHART_TYPES.map((c) => c.group))];
  return (
    <div className="chart-type-picker">
      {groups.map((group) => (
        <div key={group} className="chart-type-group">
          <div className="chart-type-group-label">{group}</div>
          <div className="chart-type-grid">
            {CHART_TYPES.filter((c) => c.group === group).map((ct) => (
              <button
                key={ct.id}
                className={`chart-type-tile${value === ct.id ? " active" : ""}${suggestion === ct.id ? " suggested" : ""}`}
                onClick={() => onChange(ct.id)}
                title={ct.label + (suggestion === ct.id ? " (suggested)" : "")}
              >
                <span className="tile-icon">{ct.icon}</span>
                <span className="tile-label">{ct.label}</span>
                {suggestion === ct.id && <span className="tile-suggest-dot" />}
              </button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Color Theme Picker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ColorThemePicker({ value, onChange }) {
  return (
    <div className="color-theme-row">
      {Object.entries(COLOR_THEMES).map(([key, theme]) => (
        <button
          key={key}
          className={`color-theme-btn${value === key ? " active" : ""}`}
          onClick={() => onChange(key)}
          title={theme.label}
        >
          <div className="color-swatches">
            {theme.colors.slice(0, 4).map((c, i) => (
              <span key={i} style={{ background: c }} className="color-swatch" />
            ))}
          </div>
          <span>{theme.label}</span>
        </button>
      ))}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Validation Banner ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ValidationBanner({ warnings }) {
  if (!warnings.length) return null;
  return (
    <div className="validation-banner" role="alert">
      <span className="validation-icon">ΓÜá</span>
      <ul className="validation-list">
        {warnings.map((w, i) => <li key={i}>{w}</li>)}
      </ul>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ SQL Preview ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function SqlPreview({ table, xField, yField, aggregation }) {
  const [open, setOpen] = useState(false);
  const [copied, setCopied] = useState(false);

  if (!table || !xField) return null;

  const sql = buildQuery({ table, xField, yField, aggregateType: aggregation ?? "sum" });

  function handleCopy() {
    navigator.clipboard?.writeText(sql).catch(() => {});
    setCopied(true);
    setTimeout(() => setCopied(false), 1800);
  }

  return (
    <div className="sql-preview">
      <button className="sql-toggle" onClick={() => setOpen((v) => !v)}>
        <span className="sql-icon">Γ¼í</span>
        <span>SQL Preview</span>
        <span className="sql-arrow">{open ? "Γû╛" : "Γû╕"}</span>
      </button>
      {open && (
        <div className="sql-panel">
          <pre className="sql-code">{sql}</pre>
          <button className="sql-copy" onClick={handleCopy}>
            {copied ? "Γ£ö Copied" : "≡ƒôï Copy"}
          </button>
        </div>
      )}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Live Preview ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const ANT_PREVIEW = {
  line: Line, area: Area, bar: Column,
  stacked_bar: Column,
  pie: Pie, donut: Pie, scatter: Scatter,
};

function LivePreview({ chart, data }) {
  if (!data?.length) {
    return (
      <div className="preview-empty">
        <span style={{ fontSize:44, opacity:0.12 }}>≡ƒôè</span>
        <p>Select X and Y fields to preview</p>
        <p style={{ fontSize:11, opacity:0.4, marginTop:4 }}>Drag columns from the schema tree</p>
      </div>
    );
  }

  const config = buildChartConfig(chart, data, chart.colorTheme);
  const Comp   = ANT_PREVIEW[chart.type];

  if (!Comp) {
    if (chart.type === "heatmap") {
      return (
        <div className="preview-empty">
          <p style={{ opacity:0.5 }}>Heatmap Preview</p>
          <p style={{ opacity:0.3, fontSize:11 }}>Will render on dashboard</p>
        </div>
      );
    }
    const palette = getColorPalette(chart.colorTheme);
    return (
      <div className="preview-empty">
        <p style={{ opacity:0.5 }}>{chart.type} ΓÇö no interactive preview</p>
        <p style={{ opacity:0.3, fontSize:11 }}>Will render on dashboard</p>
      </div>
    );
  }

  return (
    <ChartErrorBoundary>
      <Comp {...config} style={{ height:"100%" }} animation={false} />
    </ChartErrorBoundary>
  );
}

// ΓöÇΓöÇΓöÇ Aggregation buttons ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const AGGS = ["sum","count","avg","min","max"];

// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
// Builder Page
// ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
export default function Builder() {
  const navigate          = useNavigate();
  const addChart          = useStore((s) => s.addChart);
  const updateChart       = useStore((s) => s.updateChart);
  const projects          = useStore((s) => s.projects);
  const activeProjectId   = useStore((s) => s.activeProjectId);
  const activeSheetId     = useStore((s) => s.activeSheetId);
  const activeDashboardId = useStore((s) => s.activeDashboardId);
  const builderState      = useStore((s) => s.builderState);
  const setBuilderState   = useStore((s) => s.setBuilderState);
  const resetBuilderState = useStore((s) => s.resetBuilderState);

  const activeProject = projects.find((p) => p.id === activeProjectId) ?? projects[0];
  const activeSheet   = activeProject?.sheets.find((sh) => sh.id === activeSheetId) ?? activeProject?.sheets[0];
  const activeDash    = activeSheet?.dashboards.find((d) => d.id === activeDashboardId) ?? activeSheet?.dashboards[0];
  const isEditing   = !!builderState.editingChartId;

  const {
    selectedDb, selectedTable, xField, xType, yField, yType,
    chartType, title, colorTheme, legendVisible, showGrid, smooth,
    aggregation, xLabel, yLabel, groupField,
  } = builderState;

  const tableInfo   = selectedDb && selectedTable ? schema[selectedDb]?.[selectedTable] : null;
  const tableData   = tableInfo?.data ?? [];
  const previewData = xField && yField ? tableData : [];

  const suggestion = xType || yType
    ? suggestChartType(xType, yType, !!groupField).suggested
    : null;

  useEffect(() => {
    if (suggestion && !isEditing) {
      setBuilderState({ chartType: suggestion });
    }
  }, [suggestion]); // eslint-disable-line

  const { valid, warnings } = validateChartConfig({ type: chartType, xField, yField, xType, yType });
  const canAddChart = valid && !!selectedTable;

  // ΓöÇΓöÇ Unified field assignment (from click or drop) ΓöÇΓöÇ
  const handleFieldAssign = useCallback((db, tbl, field, targetZone) => {
    // Table changed ΓÇö reset
    if (selectedTable && selectedTable !== tbl) {
      setBuilderState({
        selectedDb: db, selectedTable: tbl,
        xField: null, xType: null, yField: null, yType: null, groupField: null,
      });
      // Re-schedule the actual assignment after table reset
      setTimeout(() => {
        assignToZone(db, tbl, field, targetZone);
      }, 0);
      return;
    }
    if (!selectedTable) {
      setBuilderState({ selectedDb: db, selectedTable: tbl });
    }
    assignToZone(db, tbl, field, targetZone);
  }, [selectedTable, setBuilderState]); // eslint-disable-line

  function assignToZone(db, tbl, field, targetZone) {
    if (targetZone === "x") {
      setBuilderState({ selectedDb: db, selectedTable: tbl, xField: field.name, xType: field.type });
    } else if (targetZone === "y") {
      setBuilderState({ selectedDb: db, selectedTable: tbl, yField: field.name, yType: field.type });
    } else if (targetZone === "g") {
      setBuilderState({ selectedDb: db, selectedTable: tbl, groupField: field.name });
    } else {
      // Auto-assign based on type
      if (field.type === "number") {
        setBuilderState({ selectedDb: db, selectedTable: tbl, yField: field.name, yType: field.type });
      } else {
        setBuilderState({ selectedDb: db, selectedTable: tbl, xField: field.name, xType: field.type });
      }
    }
  }

  // Drop handler for zones ΓÇö receives (field, zoneKey)
  const handleZoneDrop = useCallback((field, zone) => {
    if (!selectedTable || selectedTable !== field.name) {
      // If table not yet set, pick it from schema search
      const found = findFieldInSchema(field.name);
      if (found) {
        handleFieldAssign(found.db, found.tbl, field, zone);
      }
    } else {
      assignToZone(selectedDb, selectedTable, field, zone);
    }
  }, [selectedTable, selectedDb, handleFieldAssign]); // eslint-disable-line

  function findFieldInSchema(fieldName) {
    for (const [db, tables] of Object.entries(schema)) {
      for (const [tbl, info] of Object.entries(tables)) {
        const field = info.fields.find((f) => f.name === fieldName);
        if (field) return { db, tbl, field };
      }
    }
    return null;
  }

  // ΓöÇΓöÇ Add / Update chart ΓöÇΓöÇ
  function handleSave() {
    const chart = {
      id:           isEditing ? builderState.editingChartId : `chart-${Date.now()}`,
      db:           selectedDb,
      table:        selectedTable,
      xField,       xType,
      yField,       yType,
      groupField,
      type:         chartType,
      title:        title.trim() || `${selectedTable} ┬╖ ${xField} / ${yField}`,
      colorTheme:   colorTheme ?? "default",
      legendVisible,
      showGrid,
      smooth,
      aggregation,
      xLabel,       yLabel,
    };

    if (isEditing) {
      updateChart(builderState.editingSheetId, builderState.editingChartId, chart);
    } else {
      addChart(chart);
    }
    resetBuilderState();
    navigate("/dashboard");
  }

  return (
    <div className="builder-layout" aria-label="Chart Builder">

      {/* ΓöÇΓöÇ LEFT: Schema Tree ΓöÇΓöÇ */}
      <SchemaTree
        onFieldAssign={handleFieldAssign}
        selectedDb={selectedDb}
        selectedTable={selectedTable}
        xField={xField}
        yField={yField}
        groupField={groupField}
      />

      {/* ΓöÇΓöÇ MIDDLE: Config + Preview ΓöÇΓöÇ */}
      <div className="builder-middle">

        {/* Field Assignments ΓÇö Drag & Drop zones */}
        <div className="builder-fields-row">
          <FieldZone
            label="X Axis"
            field={xField}
            type={xType}
            onClear={() => setBuilderState({ xField: null, xType: null })}
            zone="x"
            onDrop={(field) => {
              const found = findFieldInSchema(field.name);
              if (found) handleFieldAssign(found.db, found.tbl, found.field, "x");
            }}
          />
          <FieldZone
            label="Y Axis"
            field={yField}
            type={yType}
            accent="#1677ff"
            onClear={() => setBuilderState({ yField: null, yType: null })}
            zone="y"
            onDrop={(field) => {
              const found = findFieldInSchema(field.name);
              if (found) handleFieldAssign(found.db, found.tbl, found.field, "y");
            }}
          />
          <FieldZone
            label="Group By"
            field={groupField}
            type="string"
            accent="#722ed1"
            onClear={() => setBuilderState({ groupField: null })}
            zone="g"
            onDrop={(field) => {
              const found = findFieldInSchema(field.name);
              if (found) handleFieldAssign(found.db, found.tbl, found.field, "g");
            }}
          />
        </div>

        {/* SQL Preview */}
        <SqlPreview
          table={selectedTable}
          xField={xField}
          yField={yField}
          aggregation={aggregation}
        />

        {/* Suggestion + Validation */}
        {suggestion && chartType !== suggestion && (
          <div className="suggestion-banner">
            <span>≡ƒÆí Suggested: <strong>{CHART_TYPES.find((c) => c.id === suggestion)?.label}</strong></span>
            <button className="suggestion-apply" onClick={() => setBuilderState({ chartType: suggestion })}>
              Apply ΓåÆ
            </button>
          </div>
        )}
        <ValidationBanner warnings={warnings} />

        {/* Chart Type Picker */}
        <div className="builder-section">
          <div className="builder-section-title">Chart Type</div>
          <ChartTypePicker value={chartType} suggestion={suggestion} onChange={(t) => setBuilderState({ chartType: t })} />
        </div>

        {/* Options Row */}
        <div className="builder-options-row">
          <div className="builder-option-group">
            <label className="option-label">Aggregation</label>
            <div className="agg-row">
              {AGGS.map((a) => (
                <button
                  key={a}
                  className={`agg-btn${aggregation === a ? " active" : ""}`}
                  onClick={() => setBuilderState({ aggregation: a })}
                >{a.toUpperCase()}</button>
              ))}
            </div>
          </div>
          <div className="builder-option-group">
            <label className="option-label">Options</label>
            <div className="toggle-row">
              <label className="toggle-item">
                <input type="checkbox" checked={smooth} onChange={(e) => setBuilderState({ smooth: e.target.checked })} />
                Smooth
              </label>
              <label className="toggle-item">
                <input type="checkbox" checked={showGrid} onChange={(e) => setBuilderState({ showGrid: e.target.checked })} />
                Grid
              </label>
              <label className="toggle-item">
                <input type="checkbox" checked={legendVisible} onChange={(e) => setBuilderState({ legendVisible: e.target.checked })} />
                Legend
              </label>
            </div>
          </div>
        </div>

        {/* Color theme */}
        <div className="builder-section">
          <div className="builder-section-title">Color Theme</div>
          <ColorThemePicker value={colorTheme} onChange={(t) => setBuilderState({ colorTheme: t })} />
        </div>

        {/* Title + Axis labels */}
        <div className="builder-inputs-row">
          <div className="builder-input-group">
            <label className="option-label">Chart Title</label>
            <input
              className="config-input"
              placeholder={selectedTable ? `${selectedTable} chart` : "Chart titleΓÇª"}
              value={title}
              onChange={(e) => setBuilderState({ title: e.target.value })}
            />
          </div>
          <div className="builder-input-group">
            <label className="option-label">X Label</label>
            <input className="config-input" placeholder="X axis label" value={xLabel} onChange={(e) => setBuilderState({ xLabel: e.target.value })} />
          </div>
          <div className="builder-input-group">
            <label className="option-label">Y Label</label>
            <input className="config-input" placeholder="Y axis label" value={yLabel} onChange={(e) => setBuilderState({ yLabel: e.target.value })} />
