/**
 * Dashboard.jsx ΓÇö Enterprise BI Dashboard v2
 *
 * Grid: react-grid-layout (Responsive + WidthProvider)
 *  - Breakpoints: lg / md / sm / xs
 *  - Drag, resize, compact vertical, snap to grid
 *  - Layout persisted per-sheet via Zustand + localStorage
 *  - Smooth animations, visible resize handles
 *  - Multi-sheet tabs with rename / add / remove
 *  - KPI bar, global filters, empty state
 */
import React, { useCallback, useState, useEffect, useMemo } from "react";
import { Responsive, WidthProvider } from "react-grid-layout";
import { useNavigate } from "react-router-dom";
import { useStore } from "./store";
