// WidthProvider makes the grid auto-measure its container width
const ResponsiveGridLayout = WidthProvider(Responsive);

// ΓöÇΓöÇΓöÇ Grid breakpoints & columns ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const BREAKPOINTS = { lg: 1200, md: 900, sm: 600, xs: 0 };
const COLS        = { lg: 12,   md: 10,  sm: 6,   xs: 2 };
const ROW_HEIGHT  = 80;   // px per row unit
const MARGIN      = [12, 12]; // [horizontal, vertical] gap in px

// Compute pixel height of a grid item from its row count
function itemPixelHeight(h) {
  return h * ROW_HEIGHT + (h - 1) * MARGIN[1];
}

// ΓöÇΓöÇΓöÇ Export helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function exportCSV(chart) {
  const data = datasets[chart.table] ?? [];
  if (!data.length) return;
  const keys = Object.keys(data[0]);
  const csv  = [
    keys.join(","),
    ...data.map((r) =>
      keys.map((k) => {
        const v = r[k];
        if (v === null || v === undefined) return "";
        const s = String(v);
        return s.includes(",") || s.includes('"') ? `"${s.replace(/"/g, '""')}"` : s;
      }).join(",")
    ),
  ].join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = `${chart.title}.csv`;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 500);
}

async function exportPNG(cardEl, chart) {
  try {
    if (!window.html2canvas) {
      await import("https://cdn.jsdelivr.net/npm/html2canvas@1.4.1/dist/html2canvas.min.js");
    }
    const canvas = await window.html2canvas(cardEl, { backgroundColor: null, scale: 2 });
    const a      = document.createElement("a");
    a.href       = canvas.toDataURL("image/png");
    a.download   = `${chart.title}.png`;
    a.click();
  } catch {
    alert("PNG export requires html2canvas ΓÇö add it as a dependency for full support.");
  }
}

