        ))}
      </div>
      <h2 className="empty-title">No charts yet ΓÇö Add chart to begin</h2>
      <p  className="empty-sub">Drag fields in the Chart Builder to create your first visualization</p>
      <button className="empty-cta" onClick={() => navigate("/builder")}>
        ∩╝ï Build Chart
      </button>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Dashboard Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function Dashboard() {
  const projects          = useStore((s) => s.projects);
  const activeProjectId   = useStore((s) => s.activeProjectId);
  const activeSheetId     = useStore((s) => s.activeSheetId);
  const activeDashboardId = useStore((s) => s.activeDashboardId);
  const updateLayout      = useStore((s) => s.updateLayout);
  const filters           = useStore((s) => s.filters);
  const kpiBarVisible     = useStore((s) => s.kpiBarVisible);

  // Derive active dashboard from the project hierarchy
  const activeDash = useMemo(() => {
    const project = projects.find((p) => p.id === activeProjectId) ?? projects[0];
    const sheet   = project?.sheets.find((sh) => sh.id === activeSheetId) ?? project?.sheets[0];
    return sheet?.dashboards.find((d) => d.id === activeDashboardId) ?? sheet?.dashboards[0];
  }, [projects, activeProjectId, activeSheetId, activeDashboardId]);

  const activeSheet = useMemo(() => {
    const project = projects.find((p) => p.id === activeProjectId) ?? projects[0];
    return project?.sheets.find((sh) => sh.id === activeSheetId) ?? project?.sheets[0];
  }, [projects, activeProjectId, activeSheetId]);

  const handleLayoutChange = useCallback(
    (layout) => updateLayout(activeSheet?.id, layout),
    [activeSheet?.id, updateLayout]
  );

  const hasCharts = (activeDash?.charts?.length ?? 0) > 0;

  // Create a sheet-like object for the grid (charts + layout from active dashboard)
  const dashAsSheet = useMemo(() => activeDash
    ? { ...activeDash, id: activeDash.id }
    : null,
  [activeDash]);

  return (
    <div className="page-dashboard">
      {/* Tab Bar: Sheets & Dashboards */}
      <DashboardTabBar />

      {/* KPI Bar */}
      {kpiBarVisible && hasCharts && (
        <KpiBar charts={activeDash.charts} />
      )}

      {/* Grid or Empty */}
      {!hasCharts ? (
        <EmptyState />
      ) : (
        <DashboardGrid
          sheet={dashAsSheet}
          sheetId={activeSheet?.id}
          onLayoutChange={handleLayoutChange}
          filters={filters}
        />
      )}
    </div>
  );
}

