/**
 * KpiBar.jsx ΓÇö Dashboard KPI summary cards.
 * Auto-computed from active sheet charts + their data.
 * Animated count-up on mount. Responsive horizontal scroll.
 *
 * EXTENSION: Drive from backend aggregated query results.
 */
import React, { useEffect, useState, useRef, memo } from "react";
import { datasets } from "../mockData";

// ΓöÇΓöÇΓöÇ Count-up animation hook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function useCountUp(target, duration = 900) {
  const [val, setVal] = useState(0);
  const rafRef        = useRef(null);

  useEffect(() => {
    const start  = performance.now();
    const from   = 0;
    const to     = typeof target === "number" ? target : 0;
    const isInt  = Number.isInteger(to);

    function step(now) {
      const elapsed = now - start;
      const t       = Math.min(elapsed / duration, 1);
      // Ease out cubic
      const eased   = 1 - (1 - t) ** 3;
      const current = from + (to - from) * eased;
      setVal(isInt ? Math.round(current) : parseFloat(current.toFixed(1)));
      if (t < 1) rafRef.current = requestAnimationFrame(step);
    }
    rafRef.current = requestAnimationFrame(step);
    return () => cancelAnimationFrame(rafRef.current);
  }, [target, duration]);

  return val;
}

// ΓöÇΓöÇΓöÇ Single KPI Card ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function KpiCard({ icon, label, value, sub, accent, suffix = "" }) {
  const animated = useCountUp(typeof value === "number" ? value : 0);
  return (
    <div className="kpi-card" style={{ "--kpi-accent": accent }}>
      <div className="kpi-card-icon">{icon}</div>
      <div className="kpi-card-body">
        <div className="kpi-card-value">
          {typeof value === "number"
            ? animated.toLocaleString()
            : value
          }
          {suffix && <span className="kpi-suffix">{suffix}</span>}
        </div>
        <div className="kpi-card-label">{label}</div>
        {sub && <div className="kpi-card-sub">{sub}</div>}
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ KPI Bar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const KpiBar = memo(function KpiBar({ charts }) {
  const [kpis, setKpis] = useState([]);

  useEffect(() => {
    if (!charts.length) { setKpis([]); return; }

    const allValues = charts.flatMap((chart) => {
      const data = datasets[chart.table] ?? [];
      return data.map((d) => Number(d[chart.yField])).filter((v) => !isNaN(v));
    });

    const totalRecords = charts.reduce((sum, c) => sum + (datasets[c.table]?.length ?? 0), 0);
    const maxVal       = allValues.length ? Math.max(...allValues) : 0;
    const minVal       = allValues.length ? Math.min(...allValues) : 0;
    const avgVal       = allValues.length ? allValues.reduce((a, b) => a + b, 0) / allValues.length : 0;

    // Trend: compare first half vs second half of all values
    const half  = Math.floor(allValues.length / 2);
    const first = allValues.slice(0, half).reduce((a, b) => a + b, 0) / (half || 1);
    const last  = allValues.slice(half).reduce((a, b) => a + b, 0) / ((allValues.length - half) || 1);
    const trendPct = first > 0 ? (((last - first) / first) * 100).toFixed(1) : null;
    const trendDir = trendPct > 0 ? "Γåæ" : trendPct < 0 ? "Γåô" : "ΓåÆ";

    setKpis([
      {
        icon: "≡ƒôè", label: "Charts", value: charts.length, accent: "#1677ff",
        sub: `${totalRecords.toLocaleString()} total rows`,
      },
      {
        icon: "≡ƒôê", label: "Peak Value", value: maxVal, accent: "#52c41a",
        sub: "across all charts",
      },
      {
        icon: "≡ƒôë", label: "Min Value", value: minVal, accent: "#fa8c16",
        sub: "across all charts",
      },
      {
        icon: "Γ£ª", label: "Avg Value", value: parseFloat(avgVal.toFixed(1)), accent: "#722ed1",
        sub: trendPct !== null ? `Trend ${trendDir} ${Math.abs(trendPct)}%` : undefined,
      },
    ]);
  }, [charts]);

  if (!kpis.length) return null;

  return (
    <div className="kpi-bar" role="region" aria-label="Dashboard KPIs">
      {kpis.map((k, i) => (
        <KpiCard key={i} {...k} />
      ))}
    </div>
  );
});

export default KpiBar;

/**
 * QueryBuilder.jsx
 * DBeaver-style schema tree + interactive column picker.
 * Updates the shared builderState in Zustand when user selects fields.
 */
import React, { useState } from "react";
import { schema, TYPE_BADGE, TYPE_COLOR } from "../data/mockSchema";
import { useStore } from "../store/useStore";
import { suggestChartType } from "../utils/chartUtils";
import { Line, Column } from "@ant-design/charts";
import { datasets } from "../data/mockData";
import { buildChartConfig } from "../utils/chartUtils";

// ΓöÇΓöÇΓöÇ Schema Tree ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function SchemaTree({ onSelectTable, selectedDb, selectedTable }) {
  const [openDbs, setOpenDbs] = useState(() => new Set(Object.keys(schema)));

  function toggleDb(db) {
    setOpenDbs((prev) => {
      const next = new Set(prev);
      next.has(db) ? next.delete(db) : next.add(db);
      return next;
    });
  }

  return (
    <div className="schema-tree">
      <div className="schema-tree-header">Schema Explorer</div>

      {Object.entries(schema).map(([dbKey, db]) => (
        <div key={dbKey}>
          {/* Database */}
          <div className="tree-db" onClick={() => toggleDb(dbKey)}>
            <span className="tree-arrow">{openDbs.has(dbKey) ? "Γû╛" : "Γû╕"}</span>
            <span className="tree-db-icon">≡ƒùä</span>
            {db.label}
          </div>

          {/* Tables */}
          {openDbs.has(dbKey) &&
            Object.entries(db.tables).map(([tblKey, tbl]) => {
              const isActive = selectedDb === dbKey && selectedTable === tblKey;
              return (
                <div key={tblKey}>
                  <div
                    className={`tree-table${isActive ? " active" : ""}`}
                    onClick={() => onSelectTable(dbKey, tblKey, tbl)}
                  >
                    <span className="tree-arrow" style={{ marginLeft: 8 }}>≡ƒôï</span>
                    <span style={{ flex: 1 }}>{tbl.label}</span>
                    <span className="tree-count">{tbl.fields.length}</span>
                  </div>

                  {/* Fields (always visible when table is expanded) */}
                  {isActive && tbl.fields.map((f) => (
                    <div key={f.name} className="tree-field">
                      <span
                        className="field-type-dot"
                        style={{ background: TYPE_COLOR[f.type] }}
                      />
                      <span className="tree-field-name">{f.name}</span>
                      <span className="tree-field-badge" style={{ color: TYPE_COLOR[f.type] }}>
                        {TYPE_BADGE[f.type]}
                      </span>
                    </div>
                  ))}
                </div>
              );
            })}
        </div>
      ))}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Column Picker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ColumnPicker({ tableInfo, selectedDb, selectedTable, xField, yField, onFieldClick }) {
  if (!tableInfo) {
    return (
      <div className="col-picker-empty">
        <span style={{ fontSize: 32, opacity: 0.2 }}>≡ƒæê</span>
        <p>Select a table from the schema explorer</p>
      </div>
    );
  }

  return (
    <div className="col-picker">
      <div className="col-picker-header">
        <span className="col-picker-path">{selectedDb} ΓÇ║ {selectedTable}</span>
        <span className="col-picker-hint">Click column to assign X or Y axis</span>
      </div>
      <div className="col-list">
        {tableInfo.fields.map((field) => {
          const isX = field.name === xField;
          const isY = field.name === yField;
          return (
            <button
              key={field.name}
              className={`col-item${isX ? " col-x" : ""}${isY ? " col-y" : ""}`}
              onClick={() => onFieldClick(field)}
              title={`type: ${field.type}`}
            >
              <span className="col-type-dot" style={{ background: TYPE_COLOR[field.type] }} />
              <span className="col-name">{field.name}</span>
              <span className="col-type-badge" style={{ color: TYPE_COLOR[field.type] }}>
                {TYPE_BADGE[field.type]}
              </span>
              {isX && <span className="col-axis-pill x">X</span>}
              {isY && <span className="col-axis-pill y">Y</span>}
            </button>
          );
        })}
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Live Preview ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function LivePreview({ chart }) {
  if (!chart) {
    return (
      <div className="preview-empty">
        <span className="empty-icon" style={{ fontSize: 36, opacity: 0.15 }}>≡ƒôè</span>
        <p>Select X and Y fields to preview</p>
      </div>
    );
  }

  const data   = datasets[chart.table] ?? [];
  const config = buildChartConfig(chart, data);

  return chart.type === "bar"
    ? <Column {...config} />
    : <Line   {...config} />;
}

// ΓöÇΓöÇΓöÇ Main QueryBuilder component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function QueryBuilder() {
  const builderState    = useStore((s) => s.builderState);
  const setBuilderState = useStore((s) => s.setBuilderState);

  const {
    selectedDb, selectedTable,
    xField, xType,
    yField, yType,
    chartType,
  } = builderState;

  // Current table metadata
  const tableInfo = selectedDb && selectedTable
    ? schema[selectedDb]?.tables?.[selectedTable]
    : null;

  function handleSelectTable(db, tbl, tblInfo) {
    // Reset fields when switching table
    setBuilderState({
      selectedDb: db,
      selectedTable: tbl,
      xField: null, xType: null,
      yField: null, yType: null,
      chartType: "line",
    });
  }

  function handleFieldClick(field) {
    if (field.type === "number") {
      // Numeric ΓåÆ Y axis
      setBuilderState({ yField: field.name, yType: field.type });
    } else {
      // String / date ΓåÆ X axis; auto-suggest chart type
      setBuilderState({
        xField: field.name,
        xType: field.type,
        chartType: suggestChartType(field.type),
      });
    }
  }

  // Build preview chart definition
  const previewChart = tableInfo && xField && yField
    ? { table: tableInfo.dataKey, xField, yField, type: chartType }
    : null;

  return (
    <div className="query-builder-layout">
      {/* Left: Schema tree */}
      <SchemaTree
        onSelectTable={handleSelectTable}
        selectedDb={selectedDb}
        selectedTable={selectedTable}
      />

      {/* Middle: Column picker + Live preview */}
      <div className="query-builder-middle">
        <ColumnPicker
          tableInfo={tableInfo}
          selectedDb={selectedDb}
          selectedTable={selectedTable}
          xField={xField}
          yField={yField}
          onFieldClick={handleFieldClick}
        />
        <div className="builder-preview-panel">
          <div className="builder-preview-header">
            Live Preview
            {previewChart && (
              <span className="preview-subtitle">
                ΓÇö {selectedTable} ({xField} / {yField})
              </span>
            )}
          </div>
          <div className="builder-preview-body">
            <LivePreview chart={previewChart} />
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * mockSchema.js
 * Simulates a PostgreSQL-like database schema tree.
 * Structure: database ΓåÆ table ΓåÆ field[]
 */
