        dataKey: "revenue",
        fields: [
          { name: "month", type: "string" },
          { name: "value", type: "number" },
        ],
      },
    },
  },
};

/** Flatten into an array for easy lookup */
export function findTable(db, table) {
  return schema[db]?.tables?.[table] ?? null;
}

