/**
 * SidebarRight.jsx ΓÇö Enterprise BI right control panel.
 *
 * Dashboard mode:
 *   - Add Chart CTA
 *   - Global filters
 *   - AI Insights (richer: anomaly + trend + recommendation)
 *   - Share panel
 *
 * Builder mode:
 *   - Tips + keyboard shortcuts
 *
 * PRODUCTION:
 *   - Replace mock insights with: POST /api/insights ΓåÆ ML model
 */
import React, { useState, useCallback, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { useStore } from "../store/useStore";
import FilterPanel from "../components/FilterPanel";
import { datasets } from "../mockData";

// ΓöÇΓöÇΓöÇ Statistical helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function mean(arr)   { return arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0; }
function stddev(arr) {
  const m = mean(arr);
  return Math.sqrt(arr.reduce((a, b) => a + (b - m) ** 2, 0) / (arr.length || 1));
}

// ΓöÇΓöÇΓöÇ AI Insight Generator ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function generateInsights(charts) {
  const insights = [];

  charts.forEach((chart) => {
    const data   = datasets[chart.table] ?? [];
    const values = data.map((d) => Number(d[chart.yField])).filter((v) => !isNaN(v));
    if (!values.length) return;

    const max    = Math.max(...values);
    const min    = Math.min(...values);
    const avg    = mean(values);
    const sd     = stddev(values);
    const first  = values[0];
    const last   = values[values.length - 1];
    const pct    = first > 0 ? (((last - first) / first) * 100).toFixed(1) : null;
    const maxIdx = values.indexOf(max);
    const minIdx = values.indexOf(min);
    const maxLabel = data[maxIdx]?.[chart.xField] ?? "";
    const minLabel = data[minIdx]?.[chart.xField] ?? "";

    // Trend
    const trend    = last > first ? "Γåæ Upward" : last < first ? "Γåô Downward" : "ΓåÆ Flat";
    const trendClr = last > first ? "success" : last < first ? "danger" : "neutral";

    // Anomaly: values beyond 2╧â
    const anomalies = data.filter((d) => {
      const v = Number(d[chart.yField]);
      return !isNaN(v) && Math.abs(v - avg) > 2 * sd;
    });

    insights.push({
      chartTitle: chart.title,
      items: [
        { type:"metric", icon:"≡ƒôê", text:`Peak: ${max.toLocaleString()}${maxLabel ? ` at ${maxLabel}` : ""}`, color:"success" },
        { type:"metric", icon:"≡ƒôë", text:`Low:  ${min.toLocaleString()}${minLabel ? ` at ${minLabel}` : ""}`,  color:"warning" },
        { type:"metric", icon:"Γêæ",  text:`Avg:  ${avg.toFixed(1)}  ┬╖  ╧â ${sd.toFixed(1)}`, color:"neutral" },
        { type:"trend",  icon: last > first ? "Γåæ" : last < first ? "Γåô" : "ΓåÆ",
          text:`Trend: ${trend}${pct !== null ? ` (${pct > 0 ? "+" : ""}${pct}%)` : ""}`,
          color: trendClr },
        ...(anomalies.length ? [{
          type: "anomaly",
          icon: "ΓÜá",
          text: `${anomalies.length} anomal${anomalies.length === 1 ? "y" : "ies"} detected (>2╧â)`,
          color: "warning",
        }] : []),
        ...( avg > 0 && last > avg * 1.2 ? [{
          type: "recommendation",
          icon: "≡ƒÆí",
          text: `Values trending above average ΓÇö consider a line chart for clearer trend`,
          color: "info",
        }] : []),
      ],
    });
  });

  return insights;
}

// ΓöÇΓöÇΓöÇ AI Insight Panel ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function AiInsightPanel({ charts, autoRun }) {
  const aiInsights        = useStore((s) => s.aiInsights);
  const isLoading         = useStore((s) => s.isLoadingInsights);
  const setAiInsights     = useStore((s) => s.setAiInsights);
  const setLoadingInsights = useStore((s) => s.setLoadingInsights);

  const handleGenerate = useCallback(async () => {
    if (!charts.length) return;
    setLoadingInsights(true);
    await new Promise((r) => setTimeout(r, 650));
    setAiInsights(generateInsights(charts));
  }, [charts, setAiInsights, setLoadingInsights]);

  // Auto-run when sheet changes and has charts
  useEffect(() => {
    if (autoRun && charts.length > 0) {
      handleGenerate();
    }
  }, [autoRun]); // eslint-disable-line

  const COLOR_MAP = {
    success: "var(--success)",
    warning: "var(--warning)",
    danger:  "var(--danger)",
    info:    "var(--primary)",
    neutral: "var(--text-muted)",
  };

  return (
    <div className="ai-panel">
      <div className="ai-panel-header">
        <span>≡ƒñû AI Insights</span>
        <span className="ai-badge">Mock</span>
      </div>

      <button
        className="ai-generate-btn"
        onClick={handleGenerate}
        disabled={isLoading || !charts.length}
        aria-busy={isLoading}
      >
        {isLoading
          ? <><span className="btn-spinner" aria-hidden="true" /> AnalyzingΓÇª</>
          : "ΓÜí Generate Insights"}
      </button>

      {!charts.length && <p className="ai-hint">Add charts to the dashboard first.</p>}

      {aiInsights.length > 0 && (
        <div className="ai-results">
          {aiInsights.map((group) => (
            <div key={group.chartTitle} className="ai-chart-group">
              <div className="ai-chart-title">{group.chartTitle}</div>
              {group.items.map((item, idx) => (
                <div
                  key={idx}
                  className={`ai-insight-item ai-insight-${item.type}`}
                  style={{ "--insight-color": COLOR_MAP[item.color] ?? COLOR_MAP.neutral }}
                >
                  <span className="ai-insight-icon">{item.icon}</span>
                  <span>{item.text}</span>
                </div>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

