/**
 * useStore.js ΓÇö Enterprise BI global state (v7)
 *
 * Structure:
 *   Project ΓåÆ Sheets ΓåÆ Dashboards ΓåÆ Charts
 *
 * PRODUCTION PLAN:
 *   - Replace mock login with: POST /api/auth/login ΓåÆ JWT
 *   - Replace localStorage with server-side session + react-query sync
 *   - Projects/sheets/dashboards keyed by userId on backend
 */
import { create } from "zustand";

const STORAGE_KEY = "mini-bi-v7";

// ΓöÇΓöÇΓöÇ Defaults ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const defaultDashboard = (id = "dash-1", name = "Dashboard 1") => ({
  id,
  name,
  charts: [],
  layout: [],
});

const defaultSheet = (id = "sheet-1", name = "Sheet 1") => ({
  id,
  name,
  dashboards: [defaultDashboard()],
  activeDashboardId: "dash-1",
});

const defaultProject = (id = "project-1", name = "My Project") => ({
  id,
  name,
  sheets: [defaultSheet()],
});

const defaultBuilderState = {
  selectedDb:    null,
  selectedTable: null,
  xField:        null,
  xType:         null,
  yField:        null,
  yType:         null,
  groupField:    null,
  chartType:     "bar",
  title:         "",
  colorTheme:    "default",
  legendVisible: true,
  showGrid:      true,
  smooth:        true,
  aggregation:   "sum",
  xLabel:        "",
  yLabel:        "",
};

const defaultFilters = {
  aggregateType: "sum",
  dateRange:     { start: "", end: "" },
};

// ΓöÇΓöÇΓöÇ Persistence ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function loadState() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
}

function saveState(s) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({
      projects:          s.projects,
      activeProjectId:   s.activeProjectId,
      activeSheetId:     s.activeSheetId,
      activeDashboardId: s.activeDashboardId,
      theme:             s.theme,
      user:              s.user,
      isAuthenticated:   s.isAuthenticated,
      filters:           s.filters,
      sidebarCollapsed:  s.sidebarCollapsed,
      kpiBarVisible:     s.kpiBarVisible,
    }));
  } catch {}
}

// ΓöÇΓöÇΓöÇ Migration: convert old v6 state (sheets[]) to v7 projects[] ΓöÇΓöÇ
function migrateState(saved) {
  if (!saved) return null;

  // Already v7 format
  if (saved.projects) return saved;

  // v6 had flat sheets[] ΓÇö migrate into a default project
  if (saved.sheets) {
    const sheets = saved.sheets.map((sh) => ({
      id:   sh.id,
      name: sh.name,
      activeDashboardId: `dash-${sh.id}`,
      dashboards: [{
        id:     `dash-${sh.id}`,
        name:   "Dashboard 1",
        charts: sh.charts ?? [],
        layout: sh.layout ?? [],
      }],
    }));

    return {
      ...saved,
      projects: [{
        id:     "project-1",
        name:   "My Project",
        sheets,
      }],
      activeProjectId:   "project-1",
      activeSheetId:     saved.activeSheetId ?? sheets[0]?.id ?? "sheet-1",
      activeDashboardId: sheets[0]?.activeDashboardId ?? "dash-1",
    };
  }

  return saved;
}

const saved = migrateState(loadState());

// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function getActiveProject(s) {
  return s.projects.find((p) => p.id === s.activeProjectId) ?? s.projects[0];
}

function getActiveSheet(s) {
  const project = getActiveProject(s);
  return project?.sheets.find((sh) => sh.id === s.activeSheetId) ?? project?.sheets[0];
}

function getActiveDashboard(s) {
  const sheet = getActiveSheet(s);
  return sheet?.dashboards.find((d) => d.id === s.activeDashboardId) ?? sheet?.dashboards[0];
}

// ΓöÇΓöÇΓöÇ Store ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export const useStore = create((set, get) => ({

  // ΓöÇΓöÇ Auth
  user:            saved?.user            ?? null,
  isAuthenticated: saved?.isAuthenticated ?? false,

  // ΓöÇΓöÇ Projects (top-level)
  projects:          saved?.projects          ?? [defaultProject()],
  activeProjectId:   saved?.activeProjectId   ?? "project-1",
  activeSheetId:     saved?.activeSheetId     ?? "sheet-1",
  activeDashboardId: saved?.activeDashboardId ?? "dash-1",

  // ΓöÇΓöÇ Theme
  theme: saved?.theme ?? "light",

  // ΓöÇΓöÇ Filters
  filters: saved?.filters ?? defaultFilters,

  // ΓöÇΓöÇ UI state
  sidebarCollapsed: saved?.sidebarCollapsed ?? false,
  kpiBarVisible:    saved?.kpiBarVisible    ?? true,
  mobileMenuOpen:   false,

  // ΓöÇΓöÇ Transient
  builderState:      defaultBuilderState,
  aiInsights:        [],
  isLoadingInsights: false,
  lastChartAddedAt:  null,

  // ΓöÇΓöÇ Selectors (derived)
  getActiveProject: () => getActiveProject(get()),
  getActiveSheet:   () => getActiveSheet(get()),
  getActiveDash:    () => getActiveDashboard(get()),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // AUTH
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  login: (email, _password) => set((s) => {
    const user = { id: `user-${Date.now()}`, email, name: email.split("@")[0] };
    saveState({ ...s, user, isAuthenticated: true });
    return { user, isAuthenticated: true };
  }),

  register: (email, _password) => set((s) => {
    const user = { id: `user-${Date.now()}`, email, name: email.split("@")[0] };
    saveState({ ...s, user, isAuthenticated: true });
    return { user, isAuthenticated: true };
  }),

  logout: () => set((s) => {
    saveState({ ...s, user: null, isAuthenticated: false });
    return { user: null, isAuthenticated: false, aiInsights: [], builderState: defaultBuilderState };
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // PROJECTS
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  createProject: (name) => set((s) => {
    const id      = `project-${Date.now()}`;
    const project = defaultProject(id, name);
    const projects = [...s.projects, project];
    const firstSheet = project.sheets[0];
    const firstDash  = firstSheet.dashboards[0];
    saveState({
      ...s, projects,
      activeProjectId:   id,
      activeSheetId:     firstSheet.id,
      activeDashboardId: firstDash.id,
    });
    return {
      projects,
      activeProjectId:   id,
      activeSheetId:     firstSheet.id,
      activeDashboardId: firstDash.id,
    };
  }),

  renameProject: (id, name) => set((s) => {
    const projects = s.projects.map((p) => p.id === id ? { ...p, name } : p);
    saveState({ ...s, projects });
    return { projects };
  }),

  setActiveProject: (id) => set((s) => {
    const project = s.projects.find((p) => p.id === id);
    if (!project) return {};
    const sheet = project.sheets[0];
    const dash  = sheet?.dashboards[0];
    saveState({
      ...s,
      activeProjectId:   id,
      activeSheetId:     sheet?.id,
      activeDashboardId: dash?.id,
    });
    return {
      activeProjectId:   id,
      activeSheetId:     sheet?.id ?? null,
      activeDashboardId: dash?.id  ?? null,
      aiInsights: [],
    };
  }),

  deleteProject: (id) => set((s) => {
    if (s.projects.length === 1) return {};
    const projects = s.projects.filter((p) => p.id !== id);
    const active   = s.activeProjectId === id ? projects[0] : s.projects.find((p) => p.id === s.activeProjectId);
    const sheet    = active?.sheets[0];
    const dash     = sheet?.dashboards[0];
    saveState({ ...s, projects, activeProjectId: active?.id, activeSheetId: sheet?.id, activeDashboardId: dash?.id });
    return {
      projects,
      activeProjectId:   active?.id   ?? null,
      activeSheetId:     sheet?.id    ?? null,
      activeDashboardId: dash?.id     ?? null,
    };
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // SHEETS (within active project)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  createSheet: (name) => set((s) => {
    const id    = `sheet-${Date.now()}`;
    const dashId = `dash-${Date.now() + 1}`;
    const sheet = {
      id, name,
      activeDashboardId: dashId,
      dashboards: [{ id: dashId, name: "Dashboard 1", charts: [], layout: [] }],
    };
    const projects = s.projects.map((p) =>
      p.id === s.activeProjectId
        ? { ...p, sheets: [...p.sheets, sheet] }
        : p
    );
    saveState({ ...s, projects, activeSheetId: id, activeDashboardId: dashId });
    return { projects, activeSheetId: id, activeDashboardId: dashId };
  }),

  // Kept for backwards compat (Dashboard.jsx calls addSheet)
  addSheet: () => {
    const s = get();
    const project = getActiveProject(s);
    const name = `Sheet ${(project?.sheets.length ?? 0) + 1}`;
    get().createSheet(name);
  },

  renameSheet: (id, name) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id === s.activeProjectId
        ? { ...p, sheets: p.sheets.map((sh) => sh.id === id ? { ...sh, name } : sh) }
        : p
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  removeSheet: (id) => set((s) => {
    const project = getActiveProject(s);
    if (!project || project.sheets.length <= 1) return {};
    const sheets  = project.sheets.filter((sh) => sh.id !== id);
    const activeSheetId = s.activeSheetId === id ? sheets[0].id : s.activeSheetId;
    const activeSheet   = sheets.find((sh) => sh.id === activeSheetId);
    const activeDashboardId = activeSheet?.dashboards[0]?.id ?? s.activeDashboardId;
    const projects = s.projects.map((p) =>
      p.id === s.activeProjectId ? { ...p, sheets } : p
    );
    saveState({ ...s, projects, activeSheetId, activeDashboardId });
    return { projects, activeSheetId, activeDashboardId };
  }),

  setActiveSheet: (id) => set((s) => {
    const project = getActiveProject(s);
    const sheet   = project?.sheets.find((sh) => sh.id === id);
    const dashId  = sheet?.activeDashboardId ?? sheet?.dashboards[0]?.id;
    saveState({ ...s, activeSheetId: id, activeDashboardId: dashId });
    return { activeSheetId: id, activeDashboardId: dashId ?? null, aiInsights: [] };
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // DASHBOARDS (within active sheet)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  createDashboard: (name) => set((s) => {
    const id   = `dash-${Date.now()}`;
    const dash = { id, name, charts: [], layout: [] };
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== s.activeSheetId ? sh : {
            ...sh,
            activeDashboardId: id,
            dashboards: [...sh.dashboards, dash],
          }
        ),
      }
    );
    saveState({ ...s, projects, activeDashboardId: id });
    return { projects, activeDashboardId: id };
  }),

  renameDashboard: (id, name) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== s.activeSheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) => d.id === id ? { ...d, name } : d),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  removeDashboard: (id) => set((s) => {
    const project = getActiveProject(s);
    const sheet   = getActiveSheet(s);
    if (!sheet || sheet.dashboards.length <= 1) return {};
    const dashboards = sheet.dashboards.filter((d) => d.id !== id);
    const activeDashboardId = s.activeDashboardId === id ? dashboards[0].id : s.activeDashboardId;
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== s.activeSheetId ? sh : {
            ...sh,
            dashboards,
            activeDashboardId,
          }
        ),
      }
    );
    saveState({ ...s, projects, activeDashboardId });
    return { projects, activeDashboardId };
  }),

  setActiveDashboard: (id) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== s.activeSheetId ? sh : { ...sh, activeDashboardId: id }
        ),
      }
    );
    saveState({ ...s, projects, activeDashboardId: id });
    return { projects, activeDashboardId: id, aiInsights: [] };
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // CHARTS (within active dashboard)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  addChart: (chart) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== s.activeSheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) => {
              if (d.id !== s.activeDashboardId) return d;
              const col    = d.layout.length % 3;
              const row    = Math.floor(d.layout.length / 3);
              const layout = [...d.layout, { i: chart.id, x: col * 4, y: row * 4, w: 4, h: 4, minW: 2, minH: 3 }];
              return { ...d, charts: [...d.charts, chart], layout };
            }),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects, lastChartAddedAt: Date.now() };
  }),

  updateChart: (sheetId, chartId, updates) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== sheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) => ({
              ...d,
              charts: d.charts.map((c) => c.id === chartId ? { ...c, ...updates } : c),
            })),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  duplicateChart: (sheetId, chartId) => set((s) => {
    const project = getActiveProject(s);
    const sheet   = project?.sheets.find((sh) => sh.id === sheetId);
    if (!sheet) return {};
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== sheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) => {
              if (d.id !== s.activeDashboardId) return d;
              const orig = d.charts.find((c) => c.id === chartId);
              if (!orig) return d;
              const newId    = `chart-${Date.now()}`;
              const newChart = { ...orig, id: newId, title: `${orig.title} (copy)` };
              const origL    = d.layout.find((l) => l.i === chartId);
              const newL     = origL
                ? { ...origL, i: newId, y: origL.y + origL.h }
                : { i: newId, x: 0, y: 999, w: 4, h: 4, minW: 2, minH: 3 };
              return { ...d, charts: [...d.charts, newChart], layout: [...d.layout, newL] };
            }),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  removeChart: (sheetId, chartId) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== sheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) => ({
              ...d,
              charts: d.charts.filter((c) => c.id !== chartId),
              layout: d.layout.filter((l) => l.i !== chartId),
            })),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  clearDashboard: (sheetId, dashId) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== sheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) =>
              d.id !== dashId ? d : { ...d, charts: [], layout: [] }
            ),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects, aiInsights: [] };
  }),

  // Backwards compat: clearSheet(sheetId) ΓåÆ clears active dashboard
  clearSheet: (sheetId) => {
    const s = get();
    get().clearDashboard(sheetId, s.activeDashboardId);
  },

  updateLayout: (sheetId, layout) => set((s) => {
    const projects = s.projects.map((p) =>
      p.id !== s.activeProjectId ? p : {
        ...p,
        sheets: p.sheets.map((sh) =>
          sh.id !== sheetId ? sh : {
            ...sh,
            dashboards: sh.dashboards.map((d) =>
              d.id !== s.activeDashboardId ? d : { ...d, layout }
            ),
          }
        ),
      }
    );
    saveState({ ...s, projects });
    return { projects };
  }),

  // ΓöÇΓöÇΓöÇ Backwards-compat: expose a flat `sheets` view of active project ΓöÇ
  get sheets() {
    const s = get();
    return getActiveProject(s)?.sheets ?? [];
  },

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // FILTERS
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  setFilters: (updates) => set((s) => {
    const filters = { ...s.filters, ...updates };
    saveState({ ...s, filters });
    return { filters };
  }),

  resetFilters: () => set((s) => {
    saveState({ ...s, filters: defaultFilters });
    return { filters: defaultFilters };
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // AI INSIGHTS
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  setAiInsights:      (insights) => set({ aiInsights: insights, isLoadingInsights: false }),
  setLoadingInsights: (v)        => set({ isLoadingInsights: v }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // BUILDER STATE (transient ΓÇö not persisted)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ

  setBuilderState:   (updates) => set((s) => ({ builderState: { ...s.builderState, ...updates } })),
  resetBuilderState: ()        => set({ builderState: defaultBuilderState }),

  loadChartIntoBuilder: (chart) => set({
    builderState: {
      selectedDb:     chart.db,
      selectedTable:  chart.table,
      xField:         chart.xField,
      xType:          chart.xType,
      yField:         chart.yField,
      yType:          chart.yType,
      groupField:     chart.groupField ?? null,
      chartType:      chart.type,
      title:          chart.title,
      colorTheme:     chart.colorTheme  ?? "default",
      legendVisible:  chart.legendVisible ?? true,
      showGrid:       chart.showGrid  ?? true,
      smooth:         chart.smooth    ?? true,
      aggregation:    chart.aggregation ?? "sum",
      xLabel:         chart.xLabel    ?? "",
      yLabel:         chart.yLabel    ?? "",
      editingChartId: chart.id,
      editingSheetId: chart.sheetId,
    },
  }),

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // UI
